/**
 * @summary Upload document for OCR + AI detection
 */
export const getScanDocumentUrl = () => {
  return `/api/document/scan`;
};

export const scanDocument = async (
  documentUploadBody: DocumentUploadBody,
  options?: RequestInit,
): Promise<ScanJobCreated> => {
  const formData = new FormData();
  formData.append(`file`, documentUploadBody.file);
  if (documentUploadBody.generateSummary !== undefined) {
    formData.append(
      `generateSummary`,
      documentUploadBody.generateSummary.toString(),
    );
  }
  if (documentUploadBody.extractKeywords !== undefined) {
    formData.append(
      `extractKeywords`,
      documentUploadBody.extractKeywords.toString(),
    );
  }

  return customFetch<ScanJobCreated>(getScanDocumentUrl(), {
    ...options,
    method: "POST",
    body: formData,
  });
};

